hooks.onInit:
var s = world.state;
var COLS = 7, ROWS = 4;
var X0 = 210, DX = 90, Y0 = 175, DY = 80;
s.zero = 1 * COLS + 3;            // caso cero: fila 1, columna 3 (centro-arriba)
s.R0 = 2;
s.showR0 = 0; s.showCount = 0; s.count = 0;
s.sim = false; s.showFormula = 0;

// Colores de estado.
s.C_SANO = '#d8a878';
s.C_INF = '#c9463a';
s.C_REC = '#8a94a8';
s.C_VAX = '#4f86d6';
s.C_SHIELD = '#a9cbf0';

// (Re)construye la comunidad sana. Jitter determinista por índice (sin rng),
// así el replay reproduce exactamente la misma malla.
s.build = function () {
  var p = [];
  for (var r = 0; r < ROWS; r++) {
    for (var c = 0; c < COLS; c++) {
      var i = r * COLS + c;
      var jx = Math.sin(i * 12.9898) * 7;
      var jy = Math.cos(i * 4.1414) * 6;
      p.push({
        x: X0 + c * DX + jx,
        y: Y0 + r * DY + jy,
        st: 0,        // 0 sano, 1 infectado, 2 recuperado
        vax: false,
        it: 0,        // segundos desde que se infectó
        fired: false, // ya lanzó sus contagios
        ph: i * 0.7,  // fase de respiración
      });
    }
  }
  s.people = p;
  s.edges = [];
  s.count = 0;
};

// Infecta al caso cero.
s.seed = function (idx) {
  var q = s.people[idx];
  if (q) { q.st = 1; q.it = 0; q.fired = false; s.count = 1; }
};

// Inmuniza a la mitad de la población formando una MURALLA alrededor del foco:
// deja sanos unos pocos vecinos inmediatos del caso cero (el combustible que
// arrancará el brote), inmuniza la franja siguiente (el cinturón que lo
// contiene) y deja sanos a los lejanos (protegidos por el rebaño, aunque no
// estén vacunados: esa es la joya de la inmunidad de grupo). Total ~50%, el
// umbral teórico 1 - 1/R0 = 0.5 para R0 = 2.
s.vaccinate = function (frac) {
  var zero = s.people[s.zero];
  var order = [];
  for (var i = 0; i < s.people.length; i++) {
    if (i === s.zero) continue;
    var d = Math.hypot(s.people[i].x - zero.x, s.people[i].y - zero.y);
    order.push({ i: i, d: d });
  }
  order.sort(function (a, b) { return a.d - b.d; });
  var FUEL = 3;                                   // sanos cercanos (combustible)
  var wall = Math.round(s.people.length * (frac == null ? 0.5 : frac));
  for (var k = FUEL; k < FUEL + wall && k < order.length; k++) {
    s.people[order[k].i].vax = true;
  }
};

// --- Capa global: el mundo como mapa plano (acto de la pandemia) ---
// La comunidad que acabamos de ver es apenas un punto. Aquí el planeta es un
// mapa: cada ciudad es una comunidad reducida a un puñado de micro-personas,
// las rutas son vuelos y el virus viaja en avión. La MISMA cadena que ramificó
// entre personas ramifica entre ciudades: la mecánica es fractal.
s.meshAlpha = 1;    // opacidad de la malla de personas (escala local)
s.netAlpha = 0;     // opacidad del mapa del mundo (escala global)
s.globalPhase = false;
s.travelers = [];
// Escala global: número reproductivo efectivo y la respuesta que lo revierte.
s.Reff = 2;          // R efectivo del mundo (2 en el brote; baja con las barreras)
s.reffUI = 0;        // opacidad del medidor de R
s.routeDim = 1;      // opacidad de las rutas (baja al reducir los viajes)
s.healSeeded = false;
s.globalZero = 0;    // ciudad foco: donde arranca la respuesta cuando R cae bajo 1

// Caja del mapa dentro del canvas (deja un margen de océano).
s.MAP = { x: 46, y: 46, w: 848, h: 452 };
s.mx = function (u) { return s.MAP.x + u * s.MAP.w; };
s.my = function (v) { return s.MAP.y + v * s.MAP.h; };

// Continentes como polígonos low-poly (u,v en 0..1 sobre la caja del mapa).
// Silueta estilizada, no cartográfica: basta con que se lea "mapa del mundo".
s.continents = [
  { n: 'na', pts: [[0.08,0.16],[0.18,0.10],[0.24,0.12],[0.26,0.20],[0.25,0.27],[0.27,0.33],[0.23,0.37],[0.21,0.43],[0.17,0.40],[0.15,0.33],[0.11,0.30],[0.06,0.23]] },
  { n: 'sa', pts: [[0.22,0.45],[0.27,0.47],[0.31,0.53],[0.31,0.62],[0.27,0.72],[0.23,0.79],[0.20,0.73],[0.20,0.63],[0.22,0.55],[0.20,0.49]] },
  { n: 'gr', pts: [[0.32,0.08],[0.39,0.07],[0.41,0.12],[0.35,0.16],[0.31,0.12]] },
  { n: 'eu', pts: [[0.44,0.16],[0.52,0.13],[0.56,0.17],[0.54,0.22],[0.49,0.26],[0.45,0.24],[0.43,0.19]] },
  { n: 'af', pts: [[0.46,0.28],[0.57,0.28],[0.59,0.37],[0.55,0.47],[0.50,0.55],[0.46,0.49],[0.43,0.40],[0.45,0.32]] },
  { n: 'as', pts: [[0.56,0.15],[0.66,0.10],[0.80,0.09],[0.90,0.14],[0.93,0.22],[0.85,0.26],[0.78,0.24],[0.71,0.29],[0.69,0.35],[0.66,0.31],[0.62,0.26],[0.58,0.20]] },
  { n: 'au', pts: [[0.80,0.58],[0.88,0.56],[0.92,0.62],[0.88,0.68],[0.82,0.68],[0.78,0.62]] },
  { n: 'i1', pts: [[0.74,0.40],[0.78,0.39],[0.79,0.42],[0.75,0.43]] },
  { n: 'i2', pts: [[0.81,0.41],[0.85,0.40],[0.86,0.43],[0.82,0.44]] }
];

// Ciudades sobre los continentes (u, v, esHome). La 0 es "nuestra" comunidad.
s.buildNet = function () {
  var cityUV = [
    [0.235, 0.30, true],   // 0 home (Norteamérica)
    [0.490, 0.20, false],  // 1 Europa
    [0.650, 0.27, false],  // 2 Asia (sur)
    [0.500, 0.42, false],  // 3 África
    [0.835, 0.20, false],  // 4 Asia oriental
    [0.260, 0.60, false],  // 5 Sudamérica
    [0.855, 0.62, false],  // 6 Oceanía
    [0.790, 0.41, false]   // 7 Sudeste asiático
  ];
  s.nodes = [];
  for (var i = 0; i < cityUV.length; i++) {
    var pop = [];                          // micro-población: 8 personas por ciudad
    for (var k = 0; k < 8; k++) pop.push({ a: k * Math.PI * 2 / 8, r: 10 + (k % 3) * 1.6 });
    s.nodes.push({
      x: s.mx(cityUV[i][0]), y: s.my(cityUV[i][1]),
      st: 0, it: 0, fired: false, home: cityUV[i][2], pop: pop
    });
  }
  // Rutas aéreas: malla poco profunda para que la cascada alcance todo pronto.
  s.routes = [[0,1],[0,5],[0,4],[1,3],[1,2],[1,4],[2,7],[2,4],[2,3],[3,5],[4,7],[4,6],[7,6]];
  s.travelers = [];
  s.Reff = 2; s.reffUI = 0; s.routeDim = 1; s.healSeeded = false;   // por si hay replay
};
s.seedNode = function (idx) {
  var n = s.nodes[idx];
  if (n) { n.st = 1; n.it = 0; n.fired = false; }
};

// El ícono del virus (prop v0) sobre la cabeza del caso cero.
s.showVirus = function () {
  var z = s.people[s.zero];
  var v = world.props.find(function (q) { return q.id === 'v0'; });
  if (v && z) { v.x = z.x; v.y = z.y - 46; world.tween(v, 'alpha', 1, { duration: 0.7 }); world.tween(v, 'glow', 1, { duration: 1.2 }); }
};
s.hideVirus = function () {
  var v = world.props.find(function (q) { return q.id === 'v0'; });
  if (v) { world.tween(v, 'alpha', 0, { duration: 0.6 }); world.tween(v, 'glow', 0, { duration: 0.6 }); }
};

s.build();
s.buildNet();

hooks.onStep:
var s = world.state;
if (!s.people) return;
var FIRE_DELAY = 0.55;   // s desde infectarse hasta lanzar contagios
var EDGE_TIME = 0.5;     // s que tarda una línea de contagio en cruzar
var RADIUS = 132;        // alcance de contagio (cubre vecinos cercanos)

// --- Fase global: la pandemia salta entre ciudades por los viajes ---
// La misma mecánica que entre personas, ahora entre nodos: un nodo infectado,
// tras un retardo, envía un viajero por cada ruta a sus vecinos sanos; el
// viajero cruza y enciende el nodo destino, que a su vez viaja. La red se
// vuelve roja en cascada: eso es una pandemia.
if (s.globalPhase && s.nodes) {
  var N_FIRE = 0.5, N_TRAVEL = 1.0;
  var reff = (s.Reff == null) ? 2 : s.Reff;
  var healing = reff < 1;           // por debajo de 1: la cadena se revierte

  // Al cruzar R < 1 por primera vez, la respuesta nace en la ciudad foco: la
  // MISMA cadena que propagó ahora cura (aviones azules ramificando por la red).
  if (healing && !s.healSeeded) {
    s.healSeeded = true;
    var seed = s.nodes[s.globalZero != null ? s.globalZero : 0];
    if (seed && seed.st === 1) {
      seed.st = 2; seed.it2 = 0; seed.firedHeal = false;
      world.fx.particles(seed.x, seed.y, { count: 14, color: '#7fc6a0', speed: 82, duration: 0.8, size: 2.4, spread: 6.28 });
    }
  }

  // Avanzar viajeros: rojos contagian ciudades sanas; azules curan las rojas.
  for (var v = 0; v < s.travelers.length; v++) {
    var tr = s.travelers[v];
    if (tr.done) { tr.age = (tr.age || 0) + dt; continue; }
    tr.p += dt / N_TRAVEL;
    if (tr.p >= 1) {
      tr.p = 1; tr.done = true; tr.age = 0;
      var nd = s.nodes[tr.to];
      if (!nd) continue;
      if (tr.kind === 'blue') {
        if (nd.st === 1) {
          nd.st = 2; nd.it2 = 0; nd.firedHeal = false;
          world.fx.particles(nd.x, nd.y, { count: 12, color: '#7fc6a0', speed: 70, duration: 0.7, size: 2, spread: 6.28 });
        }
      } else if (nd.st === 0) {
        nd.st = 1; nd.it = 0; nd.fired = false;
        world.fx.particles(nd.x, nd.y, { count: 10, color: '#e0663a', speed: 70, duration: 0.7, size: 2, spread: 6.28 });
      }
    }
  }
  s.travelers = s.travelers.filter(function (x) { return !(x.done && x.age > 0.5); });

  if (!healing) {
    // Brote: cada ciudad infectada, tras su retardo, viaja a las vecinas sanas.
    for (var ni = 0; ni < s.nodes.length; ni++) {
      var nn = s.nodes[ni];
      if (nn.st !== 1) continue;
      nn.it += dt;
      if (nn.fired || nn.it < N_FIRE) continue;
      nn.fired = true;
      for (var r = 0; r < s.routes.length; r++) {
        var a = s.routes[r][0], b = s.routes[r][1], other = -1;
        if (a === ni) other = b; else if (b === ni) other = a;
        if (other < 0) continue;
        var od = s.nodes[other];
        if (od.st !== 0 || od._targeted) continue;
        od._targeted = true;
        s.travelers.push({ kind: 'red', fx: nn.x, fy: nn.y, tx: od.x, ty: od.y, to: other, p: 0, done: false });
      }
    }
  } else {
    // Respuesta: cada ciudad curada envía ayuda a sus vecinas todavía rojas.
    for (var hi = 0; hi < s.nodes.length; hi++) {
      var hn = s.nodes[hi];
      if (hn.st === 1) hn.it += dt;       // el foco sigue latiendo hasta que lo curen
      if (hn.st !== 2) continue;
      hn.it2 = (hn.it2 || 0) + dt;
      if (hn.firedHeal || hn.it2 < N_FIRE) continue;
      hn.firedHeal = true;
      for (var r2 = 0; r2 < s.routes.length; r2++) {
        var a2 = s.routes[r2][0], b2 = s.routes[r2][1], o2 = -1;
        if (a2 === hi) o2 = b2; else if (b2 === hi) o2 = a2;
        if (o2 < 0) continue;
        var o2d = s.nodes[o2];
        if (o2d.st !== 1 || o2d._healTargeted) continue;
        o2d._healTargeted = true;
        s.travelers.push({ kind: 'blue', fx: hn.x, fy: hn.y, tx: o2d.x, ty: o2d.y, to: o2, p: 0, done: false });
      }
    }
  }
  return;   // en fase global no corre la sim de personas
}

// Avanzar las líneas de contagio en vuelo.
if (s.edges) {
  for (var e = 0; e < s.edges.length; e++) {
    var ed = s.edges[e];
    if (ed.done) { ed.age = (ed.age || 0) + dt; continue; }
    ed.p += dt / EDGE_TIME;
    if (ed.p >= 1) {
      ed.p = 1; ed.done = true; ed.age = 0;
      var tgt = s.people[ed.to];
      if (tgt && !ed.blocked && tgt.st === 0 && !tgt.vax) {
        tgt.st = 1; tgt.it = 0; tgt.fired = false;
        s.count = (s.count || 0) + 1;
        world.fx.particles(tgt.x, tgt.y, { count: 8, color: '#e0663a', speed: 60, duration: 0.7, size: 2, spread: 6.28 });
      } else if (ed.blocked) {
        world.fx.particles(ed.hx, ed.hy, { count: 7, color: '#a9cbf0', speed: 55, duration: 0.6, size: 2, spread: 6.28 });
      }
    }
  }
  // descartar líneas resueltas tras un breve resplandor
  s.edges = s.edges.filter(function (x) { return !(x.done && x.age > 0.45); });
}

if (!s.sim) return;

// Propagación: cada infectado que ya cumplió su retardo lanza hasta R0
// contagios hacia los vecinos sanos-no-vacunados más cercanos; si en su
// radio solo quedan vacunados, la línea sale igual y rebota en el escudo (la
// cadena se ve chocar y detenerse).
for (var i = 0; i < s.people.length; i++) {
  var p = s.people[i];
  if (p.st !== 1) continue;
  p.it += dt;   // reloj del infectado (alimenta el pulso de recién contagiado)
  // Sin recuperación automática: el infectado queda rojo toda la escena, para
  // que la marea del brote (y su contraste con la contención) se LEA en cada
  // foto. Deja de contagiar por sí solo cuando ya disparó (fired).
  if (p.fired || p.it < FIRE_DELAY) continue;
  p.fired = true;
  // candidatos: sanos aún no reservados por otra línea, más los vacunados
  // cercanos (posibles choques) si no hay sanos suficientes.
  var open = [], shields = [];
  for (var j = 0; j < s.people.length; j++) {
    if (j === i) continue;
    var q = s.people[j];
    var d = Math.hypot(q.x - p.x, q.y - p.y);
    if (d > RADIUS) continue;
    if (q.st === 0 && !q.vax && !q._targeted) open.push({ j: j, d: d });
    else if (q.vax) shields.push({ j: j, d: d });
  }
  open.sort(function (a, b) { return a.d - b.d; });
  shields.sort(function (a, b) { return a.d - b.d; });
  var picks = [];
  for (var o = 0; o < open.length && picks.length < s.R0; o++) picks.push({ j: open[o].j, vax: false });
  // completar el cupo de R0 con escudos cercanos (la cadena choca y se ve)
  for (var sh = 0; sh < shields.length && picks.length < s.R0; sh++) picks.push({ j: shields[sh].j, vax: true });
  for (var c = 0; c < picks.length; c++) {
    var q2 = s.people[picks[c].j];
    var ang = Math.atan2(q2.y - p.y, q2.x - p.x);
    var stopR = picks[c].vax ? 27 : 15;
    var hx = q2.x - Math.cos(ang) * stopR;
    var hy = q2.y - Math.sin(ang) * stopR;
    s.edges.push({ fx: p.x, fy: p.y, to: picks[c].j, p: 0, done: false, blocked: picks[c].vax, hx: hx, hy: hy });
    if (!picks[c].vax) q2._targeted = true;
  }
}

hooks.onDraw:
var s = world.state;
if (!s.people) return;
var T = world.t;
var UIQ = '"Plus Jakarta Sans", ui-sans-serif, system-ui, sans-serif';

var meshA = s.meshAlpha == null ? 1 : s.meshAlpha;
var netA = s.netAlpha == null ? 0 : s.netAlpha;

// ============ CAPA GLOBAL: el mapa del mundo plano ============
if (netA > 0.01 && s.nodes) {
  ctx.save();
  ctx.globalAlpha *= Math.min(1, netA);
  var GW = world.W || 940, GH = world.H || 580;

  // --- helpers de geometría (vuelos en arco) ---
  var bezP = function (ax, ay, cx, cy, bx, by, p) {
    var q = 1 - p;
    return [q * q * ax + 2 * q * p * cx + p * p * bx, q * q * ay + 2 * q * p * cy + p * p * by];
  };
  var arcCtrl = function (ax, ay, bx, by) {
    var mx = (ax + bx) / 2, my = (ay + by) / 2, dx = bx - ax, dy = by - ay, len = Math.hypot(dx, dy) || 1;
    var px = -dy / len, py = dx / len;
    if (py > 0) { px = -px; py = -py; }   // siempre arquea hacia arriba (norte)
    var b = Math.min(len * 0.24, 80);
    return [mx + px * b, my + py * b];
  };
  var drawPlane = function (px, py, ang, wingCol, bodyCol, tailCol) {
    ctx.save(); ctx.translate(px, py); ctx.rotate(ang);
    ctx.fillStyle = wingCol;                          // alas
    ctx.beginPath(); ctx.moveTo(1, 0); ctx.lineTo(-4, 8.5); ctx.lineTo(-1, 8.5); ctx.lineTo(2.5, 1.2); ctx.closePath(); ctx.fill();
    ctx.beginPath(); ctx.moveTo(1, 0); ctx.lineTo(-4, -8.5); ctx.lineTo(-1, -8.5); ctx.lineTo(2.5, -1.2); ctx.closePath(); ctx.fill();
    ctx.beginPath(); ctx.moveTo(-6, 0); ctx.lineTo(-9, 3.6); ctx.lineTo(-7, 3.6); ctx.lineTo(-5.5, 0.6); ctx.closePath(); ctx.fill();
    ctx.beginPath(); ctx.moveTo(-6, 0); ctx.lineTo(-9, -3.6); ctx.lineTo(-7, -3.6); ctx.lineTo(-5.5, -0.6); ctx.closePath(); ctx.fill();
    ctx.fillStyle = bodyCol;                          // fuselaje
    ctx.beginPath(); ctx.moveTo(10, 0); ctx.quadraticCurveTo(3, 2.4, -8, 2.1); ctx.quadraticCurveTo(-10, 1.4, -10, 0); ctx.quadraticCurveTo(-10, -1.4, -8, -2.1); ctx.quadraticCurveTo(3, -2.4, 10, 0); ctx.fill();
    ctx.fillStyle = tailCol;                           // cola (rojo=contagio, verde=respuesta)
    ctx.beginPath(); ctx.moveTo(-6.5, 0); ctx.lineTo(-9.5, -0.4); ctx.lineTo(-8.5, -4.2); ctx.lineTo(-6, -0.6); ctx.closePath(); ctx.fill();
    ctx.fillStyle = 'rgba(80,90,110,0.55)';           // cabina
    ctx.beginPath(); ctx.arc(6, 0, 1.3, 0, 6.283); ctx.fill();
    ctx.restore();
  };
  var HEAL = '#4ea27a', HEAL_D = '#2f6e52';           // verde salvia: ciudad a salvo

  // --- océano (mapa a sangre completa) ---
  ctx.fillStyle = '#a9bcc6';
  ctx.fillRect(0, 0, GW, GH);
  ctx.fillStyle = 'rgba(255,255,255,0.045)';           // bandas de latitud sutiles
  for (var yb = 0; yb < GH; yb += 46) ctx.fillRect(0, yb, GW, 23);
  ctx.strokeStyle = 'rgba(90,110,130,0.16)'; ctx.lineWidth = 1;   // graticule
  for (var gu = 0; gu <= 8; gu++) { var gx = s.mx(gu / 8); ctx.beginPath(); ctx.moveTo(gx, 0); ctx.lineTo(gx, GH); ctx.stroke(); }
  for (var gv = 0; gv <= 6; gv++) { var gy = s.my(gv / 6); ctx.beginPath(); ctx.moveTo(0, gy); ctx.lineTo(GW, gy); ctx.stroke(); }

  // --- continentes ---
  for (var ci = 0; ci < s.continents.length; ci++) {
    var poly = s.continents[ci].pts;
    ctx.fillStyle = 'rgba(60,70,60,0.16)';             // sombra
    ctx.beginPath();
    for (var pp = 0; pp < poly.length; pp++) { var sx = s.mx(poly[pp][0]) + 2, sy = s.my(poly[pp][1]) + 3; if (pp === 0) ctx.moveTo(sx, sy); else ctx.lineTo(sx, sy); }
    ctx.closePath(); ctx.fill();
    ctx.fillStyle = '#d7c8a1'; ctx.strokeStyle = '#b7a674'; ctx.lineWidth = 1.4;   // tierra
    ctx.beginPath();
    for (var pq = 0; pq < poly.length; pq++) { var lx = s.mx(poly[pq][0]), ly = s.my(poly[pq][1]); if (pq === 0) ctx.moveTo(lx, ly); else ctx.lineTo(lx, ly); }
    ctx.closePath(); ctx.fill(); ctx.stroke();
  }

  // --- resplandor sobre las regiones: rojo el brote, verde la recuperación ---
  for (var gi = 0; gi < s.nodes.length; gi++) {
    var gn = s.nodes[gi];
    if (gn.st === 1) {
      var gf = Math.min(1, gn.it / 1.3), rad = 28 + gf * 52;
      var grd = ctx.createRadialGradient(gn.x, gn.y, 4, gn.x, gn.y, rad);
      grd.addColorStop(0, 'rgba(201,70,58,' + (0.34 * gf).toFixed(3) + ')');
      grd.addColorStop(1, 'rgba(201,70,58,0)');
      ctx.fillStyle = grd; ctx.beginPath(); ctx.arc(gn.x, gn.y, rad, 0, 6.283); ctx.fill();
    } else if (gn.st === 2) {
      var hf = Math.min(1, (gn.it2 || 0) / 1.3), rad2 = 26 + hf * 46;
      var grd2 = ctx.createRadialGradient(gn.x, gn.y, 4, gn.x, gn.y, rad2);
      grd2.addColorStop(0, 'rgba(90,178,130,' + (0.30 * hf).toFixed(3) + ')');
      grd2.addColorStop(1, 'rgba(90,178,130,0)');
      ctx.fillStyle = grd2; ctx.beginPath(); ctx.arc(gn.x, gn.y, rad2, 0, 6.283); ctx.fill();
    }
  }

  // --- rutas aéreas: tenues, se atenúan al bajar los viajes (routeDim) ---
  var rd = s.routeDim == null ? 1 : s.routeDim;
  ctx.lineWidth = 1.3;
  for (var r = 0; r < s.routes.length; r++) {
    var na = s.nodes[s.routes[r][0]], nb = s.nodes[s.routes[r][1]];
    var rc = arcCtrl(na.x, na.y, nb.x, nb.y);
    var heal = (na.st === 2 || nb.st === 2), hot = (na.st === 1 || nb.st === 1);
    if (heal) ctx.strokeStyle = 'rgba(78,162,122,' + (0.34 * rd).toFixed(3) + ')';
    else if (hot) ctx.strokeStyle = 'rgba(201,70,58,' + (0.30 * rd).toFixed(3) + ')';
    else ctx.strokeStyle = 'rgba(70,90,110,' + (0.22 * rd).toFixed(3) + ')';
    ctx.setLineDash([5, 6]);
    ctx.beginPath(); ctx.moveTo(na.x, na.y); ctx.quadraticCurveTo(rc[0], rc[1], nb.x, nb.y); ctx.stroke();
  }
  ctx.setLineDash([]);

  // --- aviones en vuelo (viajeros) con estela ---
  for (var v = 0; v < s.travelers.length; v++) {
    var tr = s.travelers[v]; if (tr.done) continue;
    var cc = arcCtrl(tr.fx, tr.fy, tr.tx, tr.ty);
    var pt = bezP(tr.fx, tr.fy, cc[0], cc[1], tr.tx, tr.ty, tr.p);
    var pt2 = bezP(tr.fx, tr.fy, cc[0], cc[1], tr.tx, tr.ty, Math.min(1, tr.p + 0.02));
    var pang = Math.atan2(pt2[1] - pt[1], pt2[0] - pt[0]);
    var isBlue = tr.kind === 'blue';
    ctx.save(); ctx.strokeStyle = isBlue ? 'rgba(160,224,190,0.6)' : 'rgba(255,255,255,0.55)'; ctx.lineWidth = 1.6; ctx.setLineDash([2, 5]);
    ctx.beginPath();
    var stepsB = Math.max(2, Math.floor(tr.p * 18));
    for (var sb = 0; sb <= stepsB; sb++) { var cpb = bezP(tr.fx, tr.fy, cc[0], cc[1], tr.tx, tr.ty, tr.p * sb / stepsB); if (sb === 0) ctx.moveTo(cpb[0], cpb[1]); else ctx.lineTo(cpb[0], cpb[1]); }
    ctx.stroke(); ctx.setLineDash([]); ctx.restore();
    ctx.save(); ctx.globalAlpha *= 0.5; ctx.fillStyle = isBlue ? 'rgba(90,178,130,0.55)' : 'rgba(201,70,58,0.5)'; ctx.beginPath(); ctx.arc(pt[0], pt[1], 5, 0, 6.283); ctx.fill(); ctx.restore();
    if (isBlue) drawPlane(pt[0], pt[1], pang, '#dcefe4', '#eef6f0', HEAL);
    else drawPlane(pt[0], pt[1], pang, '#efe7d6', '#f6f0e4', '#c9463a');
  }

  // --- ciudades: cada una es una micro-comunidad de personas ---
  for (var i = 0; i < s.nodes.length; i++) {
    var n = s.nodes[i];
    var redFrac = n.st === 1 ? Math.min(1, n.it / 0.9) : 0;
    var nred = Math.round(redFrac * n.pop.length);
    var healFrac = n.st === 2 ? Math.min(1, (n.it2 || 0) / 0.9) : 0;
    var ngrn = Math.round(healFrac * n.pop.length);
    // halo estable de "a salvo" en las ciudades ya recuperadas
    if (n.st === 2) {
      var hp = 0.5 + 0.5 * Math.sin(T * 2 + i);
      ctx.save(); ctx.globalAlpha *= 0.18 + 0.12 * hp;
      ctx.strokeStyle = HEAL; ctx.lineWidth = 2;
      ctx.beginPath(); ctx.arc(n.x, n.y, 15, 0, 6.283); ctx.stroke(); ctx.restore();
    }
    // pulso de encendido (rojo al infectarse, verde al recuperarse)
    if (n.st === 1 && n.it < 1) {
      ctx.save(); ctx.globalAlpha *= (1 - n.it) * 0.55;
      ctx.strokeStyle = '#c9463a'; ctx.lineWidth = 2.5;
      ctx.beginPath(); ctx.arc(n.x, n.y, 16 + n.it * 26, 0, 6.283); ctx.stroke(); ctx.restore();
    } else if (n.st === 2 && (n.it2 || 0) < 1) {
      ctx.save(); ctx.globalAlpha *= (1 - (n.it2 || 0)) * 0.6;
      ctx.strokeStyle = HEAL; ctx.lineWidth = 2.5;
      ctx.beginPath(); ctx.arc(n.x, n.y, 16 + (n.it2 || 0) * 26, 0, 6.283); ctx.stroke(); ctx.restore();
    }
    for (var k = 0; k < n.pop.length; k++) {            // micro-personas
      var pa = n.pop[k].a + T * 0.12, rr = n.pop[k].r;
      var pcol = '#caa06a';
      if (n.st === 1 && k < nred) pcol = '#c9463a';
      else if (n.st === 2) pcol = k < ngrn ? HEAL : '#c9463a';
      ctx.fillStyle = pcol;
      ctx.beginPath(); ctx.arc(n.x + Math.cos(pa) * rr, n.y + Math.sin(pa) * rr * 0.7, 2.4, 0, 6.283); ctx.fill();
    }
    ctx.fillStyle = 'rgba(20,24,38,0.20)';              // marcador de ciudad
    ctx.beginPath(); ctx.ellipse(n.x, n.y + 7, 7, 2.2, 0, 0, 6.283); ctx.fill();
    ctx.fillStyle = n.st === 1 ? '#8f2b22' : (n.st === 2 ? HEAL_D : '#7a5a34');
    ctx.beginPath(); ctx.arc(n.x, n.y, 5.4, 0, 6.283); ctx.fill();
    ctx.fillStyle = n.st === 1 ? '#c9463a' : (n.st === 2 ? HEAL : '#e7cfa0');
    ctx.beginPath(); ctx.arc(n.x, n.y, 3.6, 0, 6.283); ctx.fill();
    ctx.fillStyle = 'rgba(255,255,255,0.5)';
    ctx.beginPath(); ctx.arc(n.x - 1.2, n.y - 1.2, 1.3, 0, 6.283); ctx.fill();
    if (n.home) {                                       // "nuestra" comunidad
      ctx.fillStyle = '#42506a'; ctx.font = '600 11px ' + UIQ;
      ctx.textAlign = 'center'; ctx.textBaseline = 'alphabetic';
      ctx.fillText('aquí', n.x, n.y + 24);
    }
  }

  // --- medidor de R efectivo: el número que la defensa hace bajar ---
  if (s.reffUI > 0.01) {
    ctx.save(); ctx.globalAlpha *= Math.min(1, s.reffUI);
    var reff = s.Reff == null ? 2 : s.Reff, below = reff < 1;
    var bw = 192, bh = 54, bx = 24, by = GH - bh - 44;   // esquina inferior izquierda (océano despejado)
    ctx.fillStyle = 'rgba(31,37,71,0.92)'; world.draw.rrect(bx, by, bw, bh, 11); ctx.fill();
    ctx.textAlign = 'left'; ctx.textBaseline = 'alphabetic';
    ctx.fillStyle = '#c9d2e6'; ctx.font = '600 10px ' + UIQ;
    ctx.fillText('R EFECTIVO', bx + 15, by + 18);
    ctx.fillStyle = below ? '#7fe0aa' : '#f2a24a'; ctx.font = '700 24px ' + UIQ;
    ctx.fillText(reff.toFixed(1), bx + 15, by + 44);
    var abx = bx + 74, abw = 100, aby = by + 30, abh = 8;   // barra con umbral en 1
    ctx.fillStyle = 'rgba(255,255,255,0.14)'; world.draw.rrect(abx, aby, abw, abh, 4); ctx.fill();
    var frac = Math.max(0, Math.min(1, reff / 2));
    ctx.fillStyle = below ? '#4fbf85' : '#e0663a'; world.draw.rrect(abx, aby, abw * frac, abh, 4); ctx.fill();
    ctx.strokeStyle = '#f4d58a'; ctx.lineWidth = 2;
    ctx.beginPath(); ctx.moveTo(abx + abw * 0.5, aby - 4); ctx.lineTo(abx + abw * 0.5, aby + abh + 4); ctx.stroke();
    ctx.fillStyle = '#f4d58a'; ctx.font = '600 9px ' + UIQ; ctx.textAlign = 'center';
    ctx.fillText('1', abx + abw * 0.5, aby - 7);
    ctx.restore();
  }
  ctx.restore();
}

if (meshA < 0.01) return;   // la malla de personas está oculta (fase global)
ctx.save();
ctx.globalAlpha *= Math.min(1, meshA);

// --- líneas de contagio (debajo de la gente) ---
if (s.edges) {
  for (var e = 0; e < s.edges.length; e++) {
    var ed = s.edges[e];
    var ex = ed.fx + (ed.hx - ed.fx) * Math.min(1, ed.p);
    var ey = ed.fy + (ed.hy - ed.fy) * Math.min(1, ed.p);
    ctx.save();
    var fade = ed.done ? Math.max(0, 1 - (ed.age || 0) / 0.45) : 1;
    ctx.globalAlpha = 0.9 * fade;
    ctx.strokeStyle = ed.blocked ? '#7fa8dc' : '#d8543f';
    ctx.lineWidth = 2.4;
    ctx.lineCap = 'round';
    if (ed.blocked) ctx.setLineDash([4, 4]);
    ctx.beginPath();
    ctx.moveTo(ed.fx, ed.fy);
    ctx.lineTo(ex, ey);
    ctx.stroke();
    ctx.setLineDash([]);
    // cabeza de la línea en vuelo
    if (!ed.done) {
      ctx.fillStyle = ed.blocked ? '#a9cbf0' : '#f0784f';
      ctx.beginPath(); ctx.arc(ex, ey, 3.2, 0, 6.283); ctx.fill();
    }
    ctx.restore();
  }
}

// --- personas ---
var HW = 13, HH = 15;
for (var i = 0; i < s.people.length; i++) {
  var p = s.people[i];
  var breath = Math.sin(T * 1.6 + p.ph) * 1.1;
  var cx = p.x, cy = p.y + breath;
  var col = s.C_SANO;
  if (p.vax && p.st !== 1) col = s.C_VAX;
  if (p.st === 1) col = s.C_INF;
  else if (p.st === 2) col = s.C_REC;

  // escudo de vacunado
  if (p.vax && p.st !== 1) {
    var sp = 0.5 + 0.5 * Math.sin(T * 2.2 + p.ph);
    ctx.save();
    ctx.globalAlpha = 0.32 + 0.16 * sp;
    ctx.strokeStyle = s.C_SHIELD;
    ctx.lineWidth = 2.2;
    ctx.beginPath(); ctx.arc(cx, cy - 1, HW + 8, 0, 6.283); ctx.stroke();
    ctx.globalAlpha = 0.10 + 0.06 * sp;
    ctx.fillStyle = s.C_SHIELD;
    ctx.beginPath(); ctx.arc(cx, cy - 1, HW + 8, 0, 6.283); ctx.fill();
    ctx.restore();
  }

  // pulso de recién infectado
  if (p.st === 1 && p.it < 0.9) {
    var pr = p.it / 0.9;
    ctx.save();
    ctx.globalAlpha = (1 - pr) * 0.5;
    ctx.strokeStyle = s.C_INF; ctx.lineWidth = 2.5;
    ctx.beginPath(); ctx.arc(cx, cy - 1, HW + 4 + pr * 16, 0, 6.283); ctx.stroke();
    ctx.restore();
  }

  // sombra de contacto
  ctx.fillStyle = 'rgba(20,24,38,0.16)';
  ctx.beginPath(); ctx.ellipse(p.x, p.y + HH - 1, HW * 0.82, 3.2, 0, 0, 6.283); ctx.fill();

  // cuerpo
  world.draw.rrect(cx - HW, cy - HH, HW * 2, HH * 2, 10);
  ctx.fillStyle = col; ctx.fill();
  // panza (tono claro)
  ctx.fillStyle = 'rgba(255,255,255,0.14)';
  world.draw.rrect(cx - HW, cy + 1, HW * 2, HH - 2, 8); ctx.fill();
  // ojos
  var ee = p.st === 1 ? 3.4 : 3.0;
  ctx.fillStyle = '#fbfaf6';
  ctx.beginPath(); ctx.arc(cx - 4.6, cy - 4, ee, 0, 6.283); ctx.fill();
  ctx.beginPath(); ctx.arc(cx + 4.6, cy - 4, ee, 0, 6.283); ctx.fill();
  ctx.fillStyle = '#20242f';
  var pd = 1.5;
  ctx.beginPath(); ctx.arc(cx - 4.6, cy - 3.4, pd, 0, 6.283); ctx.fill();
  ctx.beginPath(); ctx.arc(cx + 4.6, cy - 3.4, pd, 0, 6.283); ctx.fill();
  // boca preocupada del infectado
  if (p.st === 1) {
    ctx.strokeStyle = '#5a1a14'; ctx.lineWidth = 1.4; ctx.lineCap = 'round';
    ctx.beginPath(); ctx.arc(cx, cy + 6, 3, Math.PI * 1.15, Math.PI * 1.85); ctx.stroke();
  }
}

// --- contador exponencial ---
if (s.showCount > 0.01) {
  ctx.save();
  ctx.globalAlpha = Math.min(1, s.showCount);
  ctx.textAlign = 'center';
  ctx.fillStyle = '#c9463a';
  ctx.font = '700 44px ' + UIQ;
  ctx.fillText(String(s.count || 0), world.W / 2, 92);
  ctx.fillStyle = '#6E7896';
  ctx.font = '600 12px ' + UIQ;
  ctx.fillText('CONTAGIADOS', world.W / 2, 110);
  ctx.restore();
}

// --- etiqueta R0 sobre el caso cero ---
if (s.showR0 > 0.01) {
  var z = s.people[s.zero];
  ctx.save();
  ctx.globalAlpha = Math.min(1, s.showR0);
  ctx.textAlign = 'center';
  ctx.fillStyle = '#1F2547';
  world.draw.rrect(z.x - 46, z.y - 78, 92, 26, 7); ctx.fill();
  ctx.fillStyle = '#F4AC1D';
  ctx.font = '700 15px ' + UIQ;
  ctx.textBaseline = 'middle';
  ctx.fillText('R₀ = ' + (s.R0 || 2), z.x, z.y - 64);
  ctx.restore();
}

// --- fórmula del umbral de inmunidad de grupo (notación vertical apilada) ---
// Fracciones apiladas de verdad vía world.draw.math (motor de cajas del engine).
// Derivación 1 − 1/R0 = 1 − 1/2 = 1/2 para R0 = 2, con el resultado en ámbar.
if (s.showFormula > 0.01) {
  ctx.save();
  ctx.globalAlpha *= Math.min(1, s.showFormula);
  var CREAM = '#f4e8c6', AMB = '#F4AC1D';
  var FONT = { px: 22, weight: '600', family: UIQ };
  var deriv = '1 - \\frac{1}{R_0} = 1 - \\frac{1}{2} =';   // la derivación (en crema)
  var result = '\\frac{1}{2}';                             // el resultado (en ámbar)
  var dW = world.draw.measureMath(deriv, FONT).w;
  var rW = world.draw.measureMath(result, FONT).w;
  var gap = 12, total = dW + gap + rW;
  // panel
  var boxW = total + 54, boxH = 92, boxX = world.W / 2 - boxW / 2, boxY = 34;
  ctx.fillStyle = 'rgba(31,37,71,0.93)'; world.draw.rrect(boxX, boxY, boxW, boxH, 12); ctx.fill();
  ctx.strokeStyle = 'rgba(244,172,29,0.30)'; ctx.lineWidth = 1; world.draw.rrect(boxX, boxY, boxW, boxH, 12); ctx.stroke();
  // encabezado
  ctx.fillStyle = '#c9d2e6'; ctx.textAlign = 'center'; ctx.textBaseline = 'alphabetic';
  ctx.font = '600 10px ' + UIQ; ctx.letterSpacing = '1.5px';
  ctx.fillText('UMBRAL DE INMUNIDAD DE GRUPO', world.W / 2, boxY + 24);
  ctx.letterSpacing = '0px';
  // fórmula: derivación centrada + resultado ámbar a continuación
  var yMid = boxY + 60, x0 = world.W / 2 - total / 2;
  world.draw.math(x0, yMid, deriv, { px: 22, weight: '600', family: UIQ, color: CREAM, valign: 'middle' });
  world.draw.math(x0 + dW + gap, yMid, result, { px: 22, weight: '600', family: UIQ, color: AMB, valign: 'middle' });
  ctx.restore();
}

ctx.restore();   // cierra el save de la capa malla (meshAlpha)
